import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import axios from 'axios';

const AuthContext = createContext(null);

// Configure axios defaults
const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';
axios.defaults.baseURL = API_URL;

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [token, setToken] = useState(null);
  const [loading, setLoading] = useState(true);

  // Set axios Authorization header
  const setAuthHeader = useCallback((token) => {
    if (token) {
      axios.defaults.headers.common['Authorization'] = `Bearer ${token}`;
    } else {
      delete axios.defaults.headers.common['Authorization'];
    }
  }, []);

  // Initialize auth state from localStorage
  useEffect(() => {
    const storedToken = localStorage.getItem('fundit_token');
    const storedUser = localStorage.getItem('fundit_user');

    if (storedToken && storedUser) {
      try {
        const parsedUser = JSON.parse(storedUser);
        setToken(storedToken);
        setUser(parsedUser);
        setAuthHeader(storedToken);
      } catch (err) {
        localStorage.removeItem('fundit_token');
        localStorage.removeItem('fundit_user');
      }
    }

    setLoading(false);
  }, [setAuthHeader]);

  const login = (userData, jwtToken) => {
    setUser(userData);
    setToken(jwtToken);
    setAuthHeader(jwtToken);
    localStorage.setItem('fundit_token', jwtToken);
    localStorage.setItem('fundit_user', JSON.stringify(userData));
  };

  const logout = () => {
    setUser(null);
    setToken(null);
    setAuthHeader(null);
    localStorage.removeItem('fundit_token');
    localStorage.removeItem('fundit_user');
  };

  const isAuthenticated = () => !!token && !!user;
  const isAdmin = () => user?.role === 'admin';

  const value = {
    user,
    token,
    loading,
    login,
    logout,
    isAuthenticated,
    isAdmin
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

export default AuthContext;
